using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Save;

namespace TowerDefense.Data
{
    public class PlayerWallet : Singleton<PlayerWallet>
    {
        [Header("Initial Values")]
        [SerializeField] private int _initialGold = 1000;
        [SerializeField] private int _initialDiamond = 100;
        [SerializeField] private int _initialStamina = 60;

        private int _gold;
        private int _diamond;
        private int _stamina;

        public int Gold => _gold;
        public int Diamond => _diamond;
        public int Stamina => _stamina;

        public event System.Action<int> OnGoldChanged;
        public event System.Action<int> OnDiamondChanged;
        public event System.Action<int> OnStaminaChanged;

        protected override void Awake()
        {
            base.Awake();
            LoadFromSave();
        }

        private void LoadFromSave()
        {
            var save = SaveSystem.Instance?.CurrentSave;
            if (save != null && save.player != null)
            {
                // 如果存档中有钱包数据则使用，否则用初始值并写回存档
                _gold = save.player.gold > 0 || save.player.diamond > 0 || save.player.stamina > 0
                    ? save.player.gold
                    : _initialGold;
                _diamond = save.player.gold > 0 || save.player.diamond > 0 || save.player.stamina > 0
                    ? save.player.diamond
                    : _initialDiamond;
                _stamina = save.player.gold > 0 || save.player.diamond > 0 || save.player.stamina > 0
                    ? save.player.stamina
                    : _initialStamina;

                if (save.player.gold == 0 && save.player.diamond == 0 && save.player.stamina == 0)
                    PersistToSave();
            }
            else
            {
                _gold = _initialGold;
                _diamond = _initialDiamond;
                _stamina = _initialStamina;
            }
        }

        public void PersistToSave()
        {
            var save = SaveSystem.Instance?.CurrentSave;
            if (save?.player != null)
            {
                save.player.gold = _gold;
                save.player.diamond = _diamond;
                save.player.stamina = _stamina;
            }
        }

        public bool HasEnoughGold(int amount) => _gold >= amount;
        public bool HasEnoughDiamond(int amount) => _diamond >= amount;

        public void AddGold(int amount)
        {
            if (amount <= 0) return;
            _gold += amount;
            OnGoldChanged?.Invoke(_gold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _gold, Change = amount });
            PersistToSave();
        }

        public bool SpendGold(int amount)
        {
            if (!HasEnoughGold(amount)) return false;
            _gold -= amount;
            OnGoldChanged?.Invoke(_gold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _gold, Change = -amount });
            PersistToSave();
            return true;
        }

        public void AddDiamond(int amount)
        {
            if (amount <= 0) return;
            _diamond += amount;
            OnDiamondChanged?.Invoke(_diamond);
            PersistToSave();
        }

        public bool SpendDiamond(int amount)
        {
            if (!HasEnoughDiamond(amount)) return false;
            _diamond -= amount;
            OnDiamondChanged?.Invoke(_diamond);
            PersistToSave();
            return true;
        }

        public void AddStamina(int amount)
        {
            if (amount <= 0) return;
            _stamina += amount;
            OnStaminaChanged?.Invoke(_stamina);
            PersistToSave();
        }

        public bool SpendStamina(int amount)
        {
            if (_stamina < amount) return false;
            _stamina -= amount;
            OnStaminaChanged?.Invoke(_stamina);
            PersistToSave();
            return true;
        }
    }
}

