using UnityEngine;
using UnityEngine.UI;
using System.Collections.Generic;
using TowerDefense.Data;
using TowerDefense.Save;

namespace TowerDefense.UI
{
    public class QuestPanel : MonoBehaviour
    {
        [Header("Panel")]
        [SerializeField] private GameObject _questPanel;
        [SerializeField] private Button _closeButton;

        [Header("Tabs")]
        [SerializeField] private Button _tabDaily;
        [SerializeField] private Button _tabMain;
        [SerializeField] private Button _tabAchievement;
        [SerializeField] private Button _tabEvent;
        [SerializeField] private Color _tabActiveColor = new Color(1f, 0.78f, 0.2f, 1f);
        [SerializeField] private Color _tabInactiveColor = new Color(0.3f, 0.6f, 0.3f, 1f);

        [Header("Content")]
        [SerializeField] private Transform _itemContainer;
        [SerializeField] private GameObject _questItemPrefab;

        [Header("Info Bar")]
        [SerializeField] private Text _resetTimerText;
        [SerializeField] private Text _activityText;

        [Header("Activity Bar")]
        [SerializeField] private Slider _activitySlider;
        [SerializeField] private Image[] _chestIcons;
        [SerializeField] private Sprite _chestLocked;
        [SerializeField] private Sprite _chestUnlocked;
        [SerializeField] private Sprite _chestClaimed;

        [Header("Data")]
        [SerializeField] private string _jsonPath = "Data/QuestItems";

        private QuestData _questData;
        private QuestCategory _currentCategory;
        private List<GameObject> _spawnedItems = new List<GameObject>();
        private Dictionary<QuestCategory, Button> _tabButtons = new Dictionary<QuestCategory, Button>();
        private GameObject _torchRoot;
        private MovingClouds _clouds;
        private ParticleSystem _snowParticles;
        private int _snowOriginalSortOrder;

        public void SetReferences(GameObject questPanel, Button closeButton, Button tabDaily, Button tabMain, Button tabAchievement, Button tabEvent, Transform itemContainer, GameObject questItemPrefab, Text resetTimerText, Text activityText, Slider activitySlider, Image[] chestIcons)
        {
            _questPanel = questPanel;
            _closeButton = closeButton;
            _tabDaily = tabDaily;
            _tabMain = tabMain;
            _tabAchievement = tabAchievement;
            _tabEvent = tabEvent;
            _itemContainer = itemContainer;
            _questItemPrefab = questItemPrefab;
            _resetTimerText = resetTimerText;
            _activityText = activityText;
            _activitySlider = activitySlider;
            _chestIcons = chestIcons;
        }

        private void Awake()
        {
            _tabButtons[QuestCategory.Daily] = _tabDaily;
            _tabButtons[QuestCategory.Main] = _tabMain;
            _tabButtons[QuestCategory.Achievement] = _tabAchievement;
            _tabButtons[QuestCategory.Event] = _tabEvent;

            if (_closeButton != null)
                _closeButton.onClick.AddListener(CloseQuest);

            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value != null)
                {
                    var cat = kvp.Key;
                    kvp.Value.onClick.AddListener(() => SwitchTab(cat));
                }
            }

            _torchRoot = GameObject.Find("火把");

            GameObject bgObj = GameObject.Find("背景");
            if (bgObj != null)
            {
                _clouds = bgObj.GetComponent<MovingClouds>();
                _snowParticles = bgObj.GetComponentInChildren<ParticleSystem>();
                if (_snowParticles != null)
                {
                    var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                    if (renderer != null)
                        _snowOriginalSortOrder = renderer.sortingOrder;
                }
            }

            LoadQuestData();
        }

        private void Start()
        {
            if (_questPanel != null)
                _questPanel.SetActive(false);
        }

        private void LoadQuestData()
        {
            var jsonFile = Resources.Load<TextAsset>(_jsonPath);
            if (jsonFile != null)
            {
                _questData = JsonUtility.FromJson<QuestData>(jsonFile.text);
                Debug.Log($"[QuestPanel] Loaded {_questData.items.Length} quests from JSON");
            }
            else
            {
                Debug.LogError($"[QuestPanel] Failed to load JSON: Resources/{_jsonPath}");
                _questData = new QuestData { items = new QuestItemData[0], dailyActivity = 0, dailyActivityMax = 120 };
                return;
            }

            ApplySaveData();
        }

        private void ApplySaveData()
        {
            var save = SaveSystem.Instance;
            if (save == null || save.CurrentSave == null) return;

            var questSave = save.CurrentSave.quests;
            if (questSave == null || questSave.items == null || questSave.items.Count == 0) return;

            // 每日任务重置检查
            string today = System.DateTime.Now.ToString("yyyyMMdd");
            if (questSave.dailyResetDate != today)
            {
                foreach (var item in _questData.items)
                {
                    if (item.category == QuestCategory.Daily)
                    {
                        item.currentCount = 0;
                        item.status = QuestStatus.InProgress;
                    }
                }
                questSave.dailyActivity = 0;
                questSave.dailyResetDate = today;
            }
            else
            {
                _questData.dailyActivity = questSave.dailyActivity;
            }

            // 恢复每个任务的进度
            foreach (var savedItem in questSave.items)
            {
                foreach (var questItem in _questData.items)
                {
                    if (questItem.id == savedItem.id)
                    {
                        questItem.currentCount = savedItem.currentCount;
                        questItem.status = (QuestStatus)savedItem.status;
                        break;
                    }
                }
            }

            Debug.Log($"[QuestPanel] Applied save data to quests");
        }

        private void PersistQuestData()
        {
            var save = SaveSystem.Instance;
            if (save == null || save.CurrentSave == null || _questData == null) return;

            var questSave = save.CurrentSave.quests;
            questSave.items.Clear();
            questSave.dailyActivity = _questData.dailyActivity;
            questSave.dailyResetDate = System.DateTime.Now.ToString("yyyyMMdd");

            foreach (var item in _questData.items)
            {
                questSave.items.Add(new GameSaveData.QuestItemSave
                {
                    id = item.id,
                    currentCount = item.currentCount,
                    status = (int)item.status
                });
            }

            save.SaveGame();
        }

        public void OpenQuest()
        {
            if (_questPanel != null)
                _questPanel.SetActive(true);

            if (_torchRoot != null)
                _torchRoot.SetActive(false);

            if (_clouds != null)
                _clouds.IsPaused = true;

            if (_snowParticles != null)
            {
                var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (renderer != null)
                    renderer.sortingOrder = -10;
                _snowParticles.Pause(true);
            }

            ApplySaveData();
            SwitchTab(QuestCategory.Daily);
        }

        public void CloseQuest()
        {
            if (_questPanel != null)
                _questPanel.SetActive(false);

            if (_torchRoot != null)
                _torchRoot.SetActive(true);

            if (_clouds != null)
                _clouds.IsPaused = false;

            if (_snowParticles != null)
            {
                var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (renderer != null)
                    renderer.sortingOrder = _snowOriginalSortOrder;
                _snowParticles.Play(true);
            }
        }

        private void SwitchTab(QuestCategory category)
        {
            _currentCategory = category;
            UpdateTabVisuals();
            RefreshItemList();
            UpdateInfoBar();
        }

        private void UpdateTabVisuals()
        {
            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value == null) continue;
                var colors = kvp.Value.colors;
                colors.normalColor = kvp.Key == _currentCategory ? _tabActiveColor : _tabInactiveColor;
                colors.selectedColor = colors.normalColor;
                colors.highlightedColor = kvp.Key == _currentCategory ? _tabActiveColor : new Color(0.8f, 0.8f, 0.8f, 1f);
                kvp.Value.colors = colors;
            }
        }

        private void UpdateInfoBar()
        {
            if (_activityText != null && _questData != null)
                _activityText.text = $"⭐ {_questData.dailyActivity}";

            if (_activitySlider != null && _questData != null)
            {
                _activitySlider.maxValue = _questData.dailyActivityMax;
                _activitySlider.value = _questData.dailyActivity;
            }

            UpdateChestIcons();
        }

        private void UpdateChestIcons()
        {
            if (_questData == null || _chestIcons == null) return;
            int[] thresholds = { 30, 60, 90, 120 };
            for (int i = 0; i < _chestIcons.Length && i < thresholds.Length; i++)
            {
                if (_chestIcons[i] == null) continue;
                _chestIcons[i].sprite = _questData.dailyActivity >= thresholds[i] ? _chestUnlocked : _chestLocked;
            }
        }

        private void RefreshItemList()
        {
            foreach (var item in _spawnedItems)
            {
                if (item != null) DestroyImmediate(item);
            }
            _spawnedItems.Clear();

            if (_itemContainer == null || _questItemPrefab == null)
            {
                Debug.LogWarning("[QuestPanel] Item container or prefab is null");
                return;
            }

            foreach (var questData in _questData.items)
            {
                if (questData.category != _currentCategory) continue;

                GameObject itemObj = Instantiate(_questItemPrefab, _itemContainer);
                itemObj.SetActive(true);
                _spawnedItems.Add(itemObj);

                var questItemUI = itemObj.GetComponent<QuestItemUI>();
                if (questItemUI != null)
                    questItemUI.Setup(questData, this);
            }
        }

        public void OnClaimClicked(QuestItemData questData)
        {
            if (questData.status != QuestStatus.Claimable)
            {
                Debug.Log($"[QuestPanel] {questData.name} 不可领取");
                return;
            }

            var wallet = PlayerWallet.Instance;
            if (wallet == null)
            {
                Debug.LogWarning("[QuestPanel] PlayerWallet not found");
                return;
            }

            if (questData.rewards != null)
            {
                foreach (var reward in questData.rewards)
                {
                    switch (reward.rewardType)
                    {
                        case RewardType.Gold: wallet.AddGold(reward.amount); break;
                        case RewardType.Diamond: wallet.AddDiamond(reward.amount); break;
                        case RewardType.Stamina: wallet.AddStamina(reward.amount); break;
                        case RewardType.Exp: PlayerLevelSystem.Instance.AddExp(reward.amount); break;
                    }
                }
            }

            questData.status = QuestStatus.Claimed;
            _questData.dailyActivity += 10;
            Debug.Log($"[QuestPanel] 领取成功: {questData.name}");

            PersistQuestData();
            RefreshItemList();
            UpdateInfoBar();
        }

        public void OnGoToClicked(QuestItemData questData)
        {
            Debug.Log($"[QuestPanel] 前往: {questData.name}");
            CloseQuest();
        }

        public static string GetCategoryName(QuestCategory category)
        {
            return category switch
            {
                QuestCategory.Daily => "每日任务",
                QuestCategory.Main => "主线任务",
                QuestCategory.Achievement => "成就任务",
                QuestCategory.Event => "活动任务",
                _ => "未知"
            };
        }

        public static string GetRewardSymbol(RewardType type)
        {
            return type switch
            {
                RewardType.Gold => "🪙",
                RewardType.Diamond => "💎",
                RewardType.Stamina => "⚡",
                RewardType.Item => "📦",
                RewardType.Exp => "⭐",
                _ => ""
            };
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using UnityEngine.SceneManagement;
using TowerDefense.Core;
using TowerDefense.Data;

namespace TowerDefense.UI
{
    public class MainMenuUI : MonoBehaviour
    {
        [Header("Panels")]
        [SerializeField] private GameObject _mainPanel;
        [SerializeField] private GameObject _levelSelectPanel;
        [SerializeField] private GameObject _settingsPanel;

        [Header("Level Selection")]
        [SerializeField] private Transform _levelButtonContainer;
        [SerializeField] private GameObject _levelButtonPrefab;

        [Header("Settings")]
        [SerializeField] private Slider _musicSlider;
        [SerializeField] private Slider _sfxSlider;
        [SerializeField] private Toggle _fullscreenToggle;

        [Header("Currency Displays")]
        [SerializeField] private Text _goldText;
        [SerializeField] private Text _diamondText;
        [SerializeField] private Text _staminaText;
        [SerializeField] private Text _playerLevelText;
        [SerializeField] private Slider _playerExpSlider;

        [Header("Level Data")]
        [SerializeField] private LevelData[] _levels;

        private void Start()
        {
            ShowMainPanel();
            LoadSettings();
            UpdatePlayerLevelDisplay();
        }

        private void OnEnable()
        {
            var wallet = PlayerWallet.Instance;
            if (wallet != null)
            {
                wallet.OnGoldChanged += UpdateGold;
                wallet.OnDiamondChanged += UpdateDiamond;
                wallet.OnStaminaChanged += UpdateStamina;
                UpdateGold(wallet.Gold);
                UpdateDiamond(wallet.Diamond);
                UpdateStamina(wallet.Stamina);
            }

            var levelSystem = PlayerLevelSystem.Instance;
            if (levelSystem != null)
            {
                levelSystem.OnLevelChanged += UpdateLevelText;
                levelSystem.OnExpChanged += UpdateExpSlider;
                UpdatePlayerLevelDisplay();
            }
        }

        private void OnDisable()
        {
            var wallet = PlayerWallet.Instance;
            if (wallet != null)
            {
                wallet.OnGoldChanged -= UpdateGold;
                wallet.OnDiamondChanged -= UpdateDiamond;
                wallet.OnStaminaChanged -= UpdateStamina;
            }

            var levelSystem = PlayerLevelSystem.Instance;
            if (levelSystem != null)
            {
                levelSystem.OnLevelChanged -= UpdateLevelText;
                levelSystem.OnExpChanged -= UpdateExpSlider;
            }
        }

        private void UpdateGold(int amount) { if (_goldText != null) _goldText.text = amount.ToString(); }
        private void UpdateDiamond(int amount) { if (_diamondText != null) _diamondText.text = amount.ToString(); }
        private void UpdateStamina(int amount) { if (_staminaText != null) _staminaText.text = amount.ToString(); }

        public void ShowMainPanel()
        {
            if (_mainPanel != null) _mainPanel.SetActive(true);
            if (_levelSelectPanel != null) _levelSelectPanel.SetActive(false);
            if (_settingsPanel != null) _settingsPanel.SetActive(false);
        }

        public void ShowLevelSelect()
        {
            if (_mainPanel != null) _mainPanel.SetActive(false);
            if (_levelSelectPanel != null) _levelSelectPanel.SetActive(true);
            if (_settingsPanel != null) _settingsPanel.SetActive(false);

            GenerateLevelButtons();
        }

        public void ShowSettings()
        {
            if (_mainPanel != null) _mainPanel.SetActive(false);
            if (_levelSelectPanel != null) _levelSelectPanel.SetActive(false);
            if (_settingsPanel != null) _settingsPanel.SetActive(true);
        }

        public void StartLevel(int levelIndex)
        {
            if (levelIndex >= 0 && levelIndex < _levels.Length)
            {
                SceneManager.LoadScene(_levels[levelIndex].sceneName);
            }
        }

        public void QuitGame()
        {
#if UNITY_EDITOR
            UnityEditor.EditorApplication.isPlaying = false;
#else
            Application.Quit();
#endif
        }

        private void GenerateLevelButtons()
        {
            if (_levelButtonContainer == null || _levelButtonPrefab == null) return;

            foreach (Transform child in _levelButtonContainer)
            {
                Destroy(child.gameObject);
            }

            for (int i = 0; i < _levels.Length; i++)
            {
                GameObject buttonObj = Instantiate(_levelButtonPrefab, _levelButtonContainer);
                LevelButton levelButton = buttonObj.GetComponent<LevelButton>();

                if (levelButton != null)
                {
                    levelButton.Setup(_levels[i], i, this);
                }
            }
        }

        #region Settings

        public void OnMusicVolumeChanged(float value)
        {
            PlayerPrefs.SetFloat("MusicVolume", value);
            PlayerPrefs.Save();
        }

        public void OnSFXVolumeChanged(float value)
        {
            PlayerPrefs.SetFloat("SFXVolume", value);
            PlayerPrefs.Save();
        }

        public void OnFullscreenToggled(bool isFullscreen)
        {
            Screen.fullScreen = isFullscreen;
            PlayerPrefs.SetInt("Fullscreen", isFullscreen ? 1 : 0);
            PlayerPrefs.Save();
        }

        private void LoadSettings()
        {
            if (_musicSlider != null)
            {
                _musicSlider.value = PlayerPrefs.GetFloat("MusicVolume", 1f);
            }
            if (_sfxSlider != null)
            {
                _sfxSlider.value = PlayerPrefs.GetFloat("SFXVolume", 1f);
            }
            if (_fullscreenToggle != null)
            {
                _fullscreenToggle.isOn = PlayerPrefs.GetInt("Fullscreen", 1) == 1;
            }
        }

        #endregion

        #region Player Level Display

        private void UpdatePlayerLevelDisplay()
        {
            var levelSystem = PlayerLevelSystem.Instance;
            if (levelSystem == null) return;

            UpdateLevelText(levelSystem.Level);
            UpdateExpSlider(levelSystem.CurrentExp, levelSystem.ExpToNextLevel);
        }

        private void UpdateLevelText(int level)
        {
            if (_playerLevelText != null)
                _playerLevelText.text = $"Lv.{level}";
        }

        private void UpdateExpSlider(int currentExp, int expToNext)
        {
            if (_playerExpSlider != null)
            {
                _playerExpSlider.maxValue = expToNext;
                _playerExpSlider.value = currentExp;
            }
        }

        #endregion
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;

namespace TowerDefense.Core
{
    public static class EventBus
    {
        private static readonly Dictionary<Type, Delegate> _events = new Dictionary<Type, Delegate>();

        public static void Subscribe<T>(Action<T> callback) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                _events[eventType] = Delegate.Combine(_events[eventType], callback);
            }
            else
            {
                _events[eventType] = callback;
            }
        }

        public static void Unsubscribe<T>(Action<T> callback) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                _events[eventType] = Delegate.Remove(_events[eventType], callback);
            }
        }

        public static void Publish<T>(T eventData) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                (_events[eventType] as Action<T>)?.Invoke(eventData);
            }
        }

        public static void Clear()
        {
            _events.Clear();
        }
    }

    #region Event Data Structures

    public struct GameStartEvent { }
    public struct GamePauseEvent { public bool IsPaused; }
    public struct GameOverEvent { public bool IsVictory; }
    public struct WaveStartEvent { public int WaveIndex; }
    public struct WaveEndEvent { public int WaveIndex; }
    public struct EnemySpawnEvent { public GameObject Enemy; }
    public struct EnemyDeathEvent { public GameObject Enemy; public int Reward; }
    public struct EnemyReachEndEvent { public GameObject Enemy; public int Damage; }
    public struct TowerPlacedEvent { public GameObject Tower; public int Cost; }
    public struct TowerUpgradedEvent { public GameObject Tower; public int Level; }
    public struct TowerSoldEvent { public GameObject Tower; public int Refund; }
    public struct GoldChangedEvent { public int CurrentGold; public int Change; }
    public struct LifeChangedEvent { public int CurrentLife; public int Change; }
    public struct SkillUsedEvent { public string SkillName; }
    public struct ExpChangedEvent { public int Level; public int CurrentExp; public int ExpToNext; }
    public struct LevelUpEvent { public int OldLevel; public int NewLevel; }

    #endregion
}

using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Save;

namespace TowerDefense.Data
{
    public class PlayerLevelSystem : Singleton<PlayerLevelSystem>
    {
        [Header("等级配置")]
        [SerializeField] private int _maxLevel = 99;
        [SerializeField] private int _baseExp = 100;
        [SerializeField] private int _expIncrement = 50;

        private int _level = 1;
        private int _currentExp = 0;

        public int Level => _level;
        public int CurrentExp => _currentExp;
        public int MaxLevel => _maxLevel;
        public int ExpToNextLevel => GetExpRequiredForLevel(_level);
        public float ExpProgress => _level >= _maxLevel ? 1f : (float)_currentExp / ExpToNextLevel;
        public bool IsMaxLevel => _level >= _maxLevel;

        public event System.Action<int> OnLevelChanged;
        public event System.Action<int, int> OnExpChanged;

        protected override void Awake()
        {
            base.Awake();
            LoadFromSave();
        }

        /// <summary>
        /// 等级 i 所需的经验值：100 + (i-1) * 50
        /// </summary>
        public int GetExpRequiredForLevel(int level)
        {
            if (level >= _maxLevel) return int.MaxValue;
            return _baseExp + (level - 1) * _expIncrement;
        }

        /// <summary>
        /// 增加经验值，自动处理升级
        /// </summary>
        public void AddExp(int amount)
        {
            if (amount <= 0 || IsMaxLevel) return;

            int oldLevel = _level;
            _currentExp += amount;

            while (_currentExp >= ExpToNextLevel && !IsMaxLevel)
            {
                _currentExp -= ExpToNextLevel;
                _level++;
            }

            if (IsMaxLevel)
                _currentExp = 0;

            OnExpChanged?.Invoke(_currentExp, ExpToNextLevel);
            EventBus.Publish(new ExpChangedEvent { Level = _level, CurrentExp = _currentExp, ExpToNext = ExpToNextLevel });

            if (_level != oldLevel)
            {
                OnLevelChanged?.Invoke(_level);
                EventBus.Publish(new LevelUpEvent { NewLevel = _level, OldLevel = oldLevel });
                Debug.Log($"[PlayerLevelSystem] 升级! Lv.{oldLevel} → Lv.{_level}");
            }
        }

        /// <summary>
        /// 外部强制设置等级和经验（用于读档）
        /// </summary>
        public void SetLevelData(int level, int exp)
        {
            _level = Mathf.Clamp(level, 1, _maxLevel);
            _currentExp = IsMaxLevel ? 0 : Mathf.Clamp(exp, 0, ExpToNextLevel);
            OnLevelChanged?.Invoke(_level);
            OnExpChanged?.Invoke(_currentExp, ExpToNextLevel);
        }

        private void LoadFromSave()
        {
            var save = Save.SaveSystem.Instance;
            if (save != null && save.CurrentSave != null)
            {
                var player = save.CurrentSave.player;
                SetLevelData(player.playerLevel, player.playerExp);
            }
        }

        public void PersistToSave()
        {
            var save = Save.SaveSystem.Instance;
            if (save != null && save.CurrentSave != null)
            {
                save.CurrentSave.player.playerLevel = _level;
                save.CurrentSave.player.playerExp = _currentExp;
                save.SaveGame();
            }
        }

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) PersistToSave();
        }

        private void OnApplicationQuit()
        {
            PersistToSave();
        }
    }
}

