using UnityEngine;
using UnityEngine.UI;
using UnityEditor;
using UnityEditor.SceneManagement;

public static class BuildAchievementUI
{
    [MenuItem("Tools/Build Achievement UI")]
    public static void Build()
    {
        var canvas = GameObject.Find("Canvas");
        if (canvas == null) { Debug.LogError("Canvas not found"); return; }

        var canvasRect = canvas.GetComponent<RectTransform>();
        float W = canvasRect.rect.width;
        float H = canvasRect.rect.height;

        // ====== AchievementPanel Root ======
        var panelRoot = CreateUI("AchievementPanel", canvas.transform);
        var panelRect = panelRoot.GetComponent<RectTransform>();
        panelRect.anchorMin = panelRect.anchorMax = new Vector2(0.5f, 0.5f);
        panelRect.pivot = new Vector2(0.5f, 0.5f);
        panelRect.sizeDelta = new Vector2(W, H);
        var panelCanvasGroup = panelRoot.AddComponent<CanvasGroup>();
        var panelImage = panelRoot.AddComponent<Image>();
        panelImage.color = new Color(0, 0, 0, 0.55f); // semi-transparent overlay
        panelRoot.SetActive(false);

        // ====== Main Container (left-right split) ======
        var mainContainer = CreateUI("MainContainer", panelRoot.transform);
        var mcRect = mainContainer.GetComponent<RectTransform>();
        mcRect.anchorMin = mcRect.anchorMax = new Vector2(0.5f, 0.5f);
        mcRect.pivot = new Vector2(0.5f, 0.5f);
        mcRect.sizeDelta = new Vector2(1500, 780);
        var mcImage = mainContainer.AddComponent<Image>();
        mcImage.color = new Color(0.96f, 0.94f, 0.88f, 1f); // cream background
        mcImage.sprite = AssetDatabase.GetBuiltinExtraResource<Sprite>("UI/Skin/Background.psd");

        // ====== Header Bar (green top) ======
        var header = CreateUI("Header", mainContainer.transform);
        var hRect = header.GetComponent<RectTransform>();
        hRect.anchorMin = new Vector2(0, 1);
        hRect.anchorMax = new Vector2(1, 1);
        hRect.pivot = new Vector2(0.5f, 1);
        hRect.sizeDelta = new Vector2(0, 70);
        hRect.anchoredPosition = Vector2.zero;
        var hImage = header.AddComponent<Image>();
        hImage.color = new Color(0.45f, 0.75f, 0.3f, 1f); // grass green

        // Trophy icon in header
        var trophyIcon = CreateUI("TrophyIcon", header.transform);
        var tiRect = trophyIcon.GetComponent<RectTransform>();
        tiRect.sizeDelta = new Vector2(45, 45);
        tiRect.anchorMin = tiRect.anchorMax = new Vector2(0, 0.5f);
        tiRect.pivot = new Vector2(1, 0.5f);
        tiRect.anchoredPosition = new Vector2(-5, 0);
        var tiText = trophyIcon.AddComponent<Text>();
        tiText.text = "🏆";
        tiText.fontSize = 36;
        tiText.alignment = TextAnchor.MiddleCenter;
        tiText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

        // Title
        var title = CreateUI("Title", header.transform);
        var tRect = title.GetComponent<RectTransform>();
        tRect.anchorMin = tRect.anchorMax = new Vector2(0.5f, 0.5f);
        tRect.pivot = new Vector2(0.5f, 0.5f);
        tRect.sizeDelta = new Vector2(200, 50);
        var tText = title.AddComponent<Text>();
        tText.text = "成 就";
        tText.fontSize = 32;
        tText.color = Color.white;
        tText.fontStyle = FontStyle.Bold;
        tText.alignment = TextAnchor.MiddleCenter;
        tText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

        // Close button
        var closeBtn = CreateUI("CloseBtn", header.transform);
        var cbRect = closeBtn.GetComponent<RectTransform>();
        cbRect.anchorMin = new Vector2(1, 0.5f);
        cbRect.anchorMax = new Vector2(1, 0.5f);
        cbRect.pivot = new Vector2(1, 0.5f);
        cbRect.sizeDelta = new Vector2(50, 50);
        cbRect.anchoredPosition = new Vector2(-10, 0);
        var cbImage = closeBtn.AddComponent<Image>();
        cbImage.color = new Color(1f, 1f, 1f, 0.3f);
        var cbButton = closeBtn.AddComponent<Button>();
        var cbTxt = CreateUI("X", closeBtn.transform).AddComponent<Text>();
        var cbTxtRect = cbTxt.GetComponent<RectTransform>();
        cbTxtRect.anchorMin = Vector2.zero; cbTxtRect.anchorMax = Vector2.one;
        cbTxtRect.sizeDelta = Vector2.zero;
        cbTxt.text = "✕"; cbTxt.fontSize = 28; cbTxt.color = Color.white;
        cbTxt.alignment = TextAnchor.MiddleCenter;
        cbTxt.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

        // ====== Progress Bar Area ======
        var progressArea = CreateUI("ProgressArea", mainContainer.transform);
        var paRect = progressArea.GetComponent<RectTransform>();
        paRect.anchorMin = new Vector2(0, 1);
        paRect.anchorMax = new Vector2(1, 1);
        paRect.pivot = new Vector2(0.5f, 1);
        paRect.sizeDelta = new Vector2(-20, 50);
        paRect.anchoredPosition = new Vector2(0, -80);
        var paBg = progressArea.AddComponent<Image>();
        paBg.color = new Color(0.92f, 0.9f, 0.82f, 1f);

        // Total count text
        var totalCount = CreateUI("TotalCount", progressArea.transform);
        var tcRect = totalCount.GetComponent<RectTransform>();
        tcRect.anchorMin = new Vector2(0, 0.5f);
        tcRect.anchorMax = new Vector2(0, 0.5f);
        tcRect.pivot = new Vector2(0, 0.5f);
        tcRect.sizeDelta = new Vector2(80, 30);
        tcRect.anchoredPosition = new Vector2(15, 0);
        var tcText = totalCount.AddComponent<Text>();
        tcText.text = "0/28";
        tcText.fontSize = 18;
        tcText.fontStyle = FontStyle.Bold;
        tcText.color = new Color(0.3f, 0.25f, 0.15f, 1f);
        tcText.alignment = TextAnchor.MiddleLeft;
        tcText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

        // Total progress slider
        var progSlider = CreateUI("ProgressSlider", progressArea.transform);
        var psRect = progSlider.GetComponent<RectTransform>();
        psRect.anchorMin = psRect.anchorMax = new Vector2(0.5f, 0.5f);
        psRect.pivot = new Vector2(0.5f, 0.5f);
        psRect.sizeDelta = new Vector2(900, 16);
        var psSlider = progSlider.AddComponent<Slider>();
        var psBg = progSlider.AddComponent<Image>();
        psBg.color = new Color(0.8f, 0.75f, 0.65f, 1f);
        psSlider.targetGraphic = psBg;

        // Slider fill
        var fillArea = CreateUI("Fill Area", progSlider.transform);
        var faRect = fillArea.GetComponent<RectTransform>();
        faRect.anchorMin = faRect.anchorMax = new Vector2(0.5f, 0.5f);
        faRect.pivot = new Vector2(0.5f, 0.5f);
        faRect.sizeDelta = new Vector2(0, 0);

        var fill = CreateUI("Fill", fillArea.transform);
        var fRect = fill.GetComponent<RectTransform>();
        fRect.anchorMin = Vector2.zero; fRect.anchorMax = Vector2.one;
        fRect.sizeDelta = Vector2.zero;
        var fImage = fill.AddComponent<Image>();
        fImage.color = new Color(0.45f, 0.8f, 0.3f, 1f);
        psSlider.fillRect = fRect;
        psSlider.handleRect = null;

        // Percent text
        var pctText = CreateUI("Percent", progressArea.transform);
        var pctRect = pctText.GetComponent<RectTransform>();
        pctRect.anchorMin = new Vector2(1, 0.5f);
        pctRect.anchorMax = new Vector2(1, 0.5f);
        pctRect.pivot = new Vector2(1, 0.5f);
        pctRect.sizeDelta = new Vector2(60, 30);
        pctRect.anchoredPosition = new Vector2(-15, 0);
        var pctTxt = pctText.AddComponent<Text>();
        pctTxt.text = "0%";
        pctTxt.fontSize = 16;
        pctTxt.color = new Color(0.45f, 0.75f, 0.3f, 1f);
        pctTxt.alignment = TextAnchor.MiddleRight;
        pctTxt.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

        // ====== Left Tab Area ======
        var leftPanel = CreateUI("LeftPanel", mainContainer.transform);
        var lpRect = leftPanel.GetComponent<RectTransform>();
        lpRect.anchorMin = new Vector2(0, 0);
        lpRect.anchorMax = new Vector2(0, 1);
        lpRect.pivot = new Vector2(0, 0.5f);
        lpRect.sizeDelta = new Vector2(180, -140);
        lpRect.anchoredPosition = new Vector2(10, -5);
        var lpImage = leftPanel.AddComponent<Image>();
        lpImage.color = new Color(0.93f, 0.91f, 0.84f, 1f);

        var lpVLG = leftPanel.AddComponent<VerticalLayoutGroup>();
        lpVLG.padding = new RectOffset(5, 5, 10, 10);
        lpVLG.spacing = 8;
        lpVLG.childAlignment = TextAnchor.UpperCenter;
        lpVLG.childControlWidth = true;
        lpVLG.childControlHeight = false;
        lpVLG.childForceExpandWidth = true;
        lpVLG.childForceExpandHeight = false;

        // Create 6 tab buttons
        string[] tabNames = { "全部", "成长", "战斗", "收集", "探索", "趣味" };
        Button[] tabBtns = new Button[6];
        for (int i = 0; i < 6; i++)
        {
            var tab = CreateUI($"Tab_{tabNames[i]}", leftPanel.transform);
            var tabBtn = tab.AddComponent<Button>();
            var tabImg = tab.AddComponent<Image>();
            tabImg.color = i == 0 ? new Color(0.45f, 0.75f, 0.3f, 1f) : new Color(0.95f, 0.93f, 0.85f, 1f);

            var tabTextObj = CreateUI("Label", tab.transform);
            var ttRect = tabTextObj.GetComponent<RectTransform>();
            ttRect.anchorMin = ttRect.anchorMax = new Vector2(0.5f, 0.5f);
            ttRect.pivot = new Vector2(0.5f, 0.5f);
            ttRect.sizeDelta = new Vector2(0, 0);
            var ttText = tabTextObj.AddComponent<Text>();
            ttText.text = tabNames[i];
            ttText.fontSize = 20;
            ttText.color = i == 0 ? Color.white : new Color(0.3f, 0.25f, 0.15f, 1f);
            ttText.alignment = TextAnchor.MiddleCenter;
            ttText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

            var tabLH = tab.AddComponent<LayoutElement>();
            tabLH.preferredHeight = 50;
            tabLH.minHeight = 40;

            var colors = tabBtn.colors;
            colors.fadeDuration = 0.15f;
            tabBtn.colors = colors;
            tabBtns[i] = tabBtn;
        }

        // ====== Right Content Area ======
        var rightPanel = CreateUI("RightPanel", mainContainer.transform);
        var rpRect = rightPanel.GetComponent<RectTransform>();
        rpRect.anchorMin = new Vector2(0, 0);
        rpRect.anchorMax = new Vector2(1, 1);
        rpRect.pivot = new Vector2(0.5f, 0.5f);
        rpRect.sizeDelta = new Vector2(-200, -140);
        rpRect.anchoredPosition = new Vector2(85, -5);

        // Scroll View for items
        var scrollView = CreateUI("ScrollView", rightPanel.transform);
        var svRect = scrollView.GetComponent<RectTransform>();
        svRect.anchorMin = svRect.anchorMax = Vector2.zero;
        svRect.anchorMin = new Vector2(0, 0.08f);
        svRect.anchorMax = Vector2.one;
        svRect.sizeDelta = Vector2.zero;
        var scrollRect = scrollView.AddComponent<ScrollRect>();
        var svImg = scrollView.AddComponent<Image>();
        svImg.color = new Color(0.94f, 0.92f, 0.86f, 1f);
        var svMask = scrollView.AddComponent<Mask>();
        svMask.showMaskGraphic = false;

        // Viewport content
        var content = CreateUI("Content", scrollView.transform);
        var cRect = content.GetComponent<RectTransform>();
        cRect.anchorMin = new Vector2(0, 1);
        cRect.anchorMax = new Vector2(1, 1);
        cRect.pivot = new Vector2(0.5f, 1);
        cRect.sizeDelta = new Vector2(0, 0);
        var cVLG = content.AddComponent<VerticalLayoutGroup>();
        cVLG.padding = new RectOffset(10, 10, 10, 10);
        cVLG.spacing = 8;
        cVLG.childControlWidth = true;
        cVLG.childControlHeight = false;
        cVLG.childForceExpandWidth = true;
        cVLG.childForceExpandHeight = false;
        var cFitter = content.AddComponent<ContentSizeFitter>();
        cFitter.verticalFit = ContentSizeFitter.FitMode.PreferredSize;

        scrollRect.content = cRect;
        scrollRect.viewport = svRect;
        scrollRect.horizontal = false;
        scrollRect.vertical = true;

        // ====== Achievement Item Prefab ======
        var itemPrefab = CreateUI("AchievementItem", null);
        var ipRect = itemPrefab.GetComponent<RectTransform>();
        var ipImg = itemPrefab.AddComponent<Image>();
        ipImg.color = new Color(1f, 0.99f, 0.95f, 1f);
        var ipLE = itemPrefab.AddComponent<LayoutElement>();
        ipLE.preferredHeight = 90;
        ipLE.minHeight = 80;

        // Icon BG (hexagon-like)
        var iconBg = CreateUI("IconBg", itemPrefab.transform);
        var ibRect = iconBg.GetComponent<RectTransform>();
        ibRect.anchorMin = new Vector2(0, 0.5f);
        ibRect.anchorMax = new Vector2(0, 0.5f);
        ibRect.pivot = new Vector2(0, 0.5f);
        ibRect.sizeDelta = new Vector2(70, 70);
        ibRect.anchoredPosition = new Vector2(10, 0);
        var ibImg = iconBg.AddComponent<Image>();
        ibImg.color = new Color(1f, 0.84f, 0.2f, 1f); // gold default

        // Icon symbol text
        var iconSym = CreateUI("IconSymbol", iconBg.transform);
        var isRect = iconSym.GetComponent<RectTransform>();
        isRect.anchorMin = isRect.anchorMax = Vector2.zero;
        isRect.anchorMin = Vector2.zero; isRect.anchorMax = Vector2.one;
        isRect.sizeDelta = Vector2.zero;
        var isText = iconSym.AddComponent<Text>();
        isText.text = "🏆";
        isText.fontSize = 30;
        isText.alignment = TextAnchor.MiddleCenter;
        isText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

        // Text area (name + desc + progress)
        var textArea = CreateUI("TextArea", itemPrefab.transform);
        var taRect = textArea.GetComponent<RectTransform>();
        taRect.anchorMin = new Vector2(0, 0.5f);
        taRect.anchorMax = new Vector2(0, 0.5f);
        taRect.pivot = new Vector2(0, 0.5f);
        taRect.sizeDelta = new Vector2(500, 70);
        taRect.anchoredPosition = new Vector2(95, 0);

        // Name
        var nameTxt = CreateUI("Name", textArea.transform);
        var nRect = nameTxt.GetComponent<RectTransform>();
        nRect.anchorMin = new Vector2(0, 1);
        nRect.anchorMax = new Vector2(1, 1);
        nRect.pivot = new Vector2(0, 1);
        nRect.sizeDelta = new Vector2(0, 28);
        nRect.anchoredPosition = new Vector2(0, 0);
        var nText = nameTxt.AddComponent<Text>();
        nText.text = "成就名称";
        nText.fontSize = 18;
        nText.fontStyle = FontStyle.Bold;
        nText.color = new Color(0.2f, 0.15f, 0.1f, 1f);
        nText.alignment = TextAnchor.MiddleLeft;
        nText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

        // Description
        var descTxt = CreateUI("Desc", textArea.transform);
        var dRect = descTxt.GetComponent<RectTransform>();
        dRect.anchorMin = new Vector2(0, 0.5f);
        dRect.anchorMax = new Vector2(1, 0.5f);
        dRect.pivot = new Vector2(0, 0.5f);
        dRect.sizeDelta = new Vector2(0, 20);
        dRect.anchoredPosition = new Vector2(0, 0);
        var dText = descTxt.AddComponent<Text>();
        dText.text = "完成条件描述";
        dText.fontSize = 14;
        dText.color = new Color(0.5f, 0.45f, 0.35f, 1f);
        dText.alignment = TextAnchor.MiddleLeft;
        dText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

        // Progress bar row
        var progRow = CreateUI("ProgressRow", textArea.transform);
        var prRect = progRow.GetComponent<RectTransform>();
        prRect.anchorMin = new Vector2(0, 0);
        prRect.anchorMax = new Vector2(1, 0);
        prRect.pivot = new Vector2(0, 0);
        prRect.sizeDelta = new Vector2(0, 20);
        prRect.anchoredPosition = new Vector2(0, 0);

        var itemSlider = CreateUI("ItemSlider", progRow.transform);
        var isldRect = itemSlider.GetComponent<RectTransform>();
        isldRect.anchorMin = isldRect.anchorMax = new Vector2(0, 0.5f);
        isldRect.pivot = new Vector2(0, 0.5f);
        isldRect.sizeDelta = new Vector2(350, 12);
        isldRect.anchoredPosition = new Vector2(0, 0);
        var isldSlider = itemSlider.AddComponent<Slider>();
        var isldBg = itemSlider.AddComponent<Image>();
        isldBg.color = new Color(0.82f, 0.78f, 0.7f, 1f);
        isldSlider.targetGraphic = isldBg;

        var ifillArea = CreateUI("FillArea", itemSlider.transform);
        var ifaRect = ifillArea.GetComponent<RectTransform>();
        ifaRect.anchorMin = ifaRect.anchorMax = new Vector2(0.5f, 0.5f);
        ifaRect.pivot = new Vector2(0.5f, 0.5f);
        ifaRect.sizeDelta = Vector2.zero;

        var ifill = CreateUI("Fill", ifillArea.transform);
        var ifRect = ifill.GetComponent<RectTransform>();
        ifRect.anchorMin = Vector2.zero; ifRect.anchorMax = Vector2.one;
        ifRect.sizeDelta = Vector2.zero;
        var ifImg = ifill.AddComponent<Image>();
        ifImg.color = new Color(0.45f, 0.8f, 0.3f, 1f);
        isldSlider.fillRect = ifRect;
        isldSlider.handleRect = null;

        var progLabel = CreateUI("ProgressLabel", progRow.transform);
        var plRect = progLabel.GetComponent<RectTransform>();
        plRect.anchorMin = new Vector2(0, 0.5f);
        plRect.anchorMax = new Vector2(0, 0.5f);
        plRect.pivot = new Vector2(0, 0.5f);
        plRect.sizeDelta = new Vector2(80, 20);
        plRect.anchoredPosition = new Vector2(360, 0);
        var plText = progLabel.AddComponent<Text>();
        plText.text = "0/10";
        plText.fontSize = 14;
        plText.color = new Color(0.4f, 0.35f, 0.25f, 1f);
        plText.alignment = TextAnchor.MiddleLeft;
        plText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

        // Right side: reward + button
        var rightSide = CreateUI("RightSide", itemPrefab.transform);
        var rsRect = rightSide.GetComponent<RectTransform>();
        rsRect.anchorMin = new Vector2(1, 0.5f);
        rsRect.anchorMax = new Vector2(1, 0.5f);
        rsRect.pivot = new Vector2(1, 0.5f);
        rsRect.sizeDelta = new Vector2(200, 70);
        rsRect.anchoredPosition = new Vector2(-10, 0);

        var rewardLabel = CreateUI("RewardLabel", rightSide.transform);
        var rlRect = rewardLabel.GetComponent<RectTransform>();
        rlRect.anchorMin = new Vector2(0, 0.5f);
        rlRect.anchorMax = new Vector2(1, 0.5f);
        rlRect.pivot = new Vector2(0.5f, 1);
        rlRect.sizeDelta = new Vector2(0, 22);
        rlRect.anchoredPosition = new Vector2(0, -5);
        var rlText = rewardLabel.AddComponent<Text>();
        rlText.text = "🪙×100  💎×10";
        rlText.fontSize = 14;
        rlText.color = new Color(0.5f, 0.4f, 0.2f, 1f);
        rlText.alignment = TextAnchor.MiddleCenter;
        rlText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

        var claimBtn = CreateUI("ClaimBtn", rightSide.transform);
        var clbRect = claimBtn.GetComponent<RectTransform>();
        clbRect.anchorMin = new Vector2(0.5f, 0);
        clbRect.anchorMax = new Vector2(0.5f, 0);
        clbRect.pivot = new Vector2(0.5f, 0);
        clbRect.sizeDelta = new Vector2(100, 34);
        clbRect.anchoredPosition = new Vector2(0, 5);
        var clbImg = claimBtn.AddComponent<Image>();
        clbImg.color = new Color(1f, 0.75f, 0.15f, 1f); // gold/yellow
        var clbButton = claimBtn.AddComponent<Button>();
        var clbLabel = CreateUI("Label", claimBtn.transform);
        var clblRect = clbLabel.GetComponent<RectTransform>();
        clblRect.anchorMin = clblRect.anchorMax = Vector2.zero;
        clblRect.anchorMin = Vector2.zero; clblRect.anchorMax = Vector2.one;
        clblRect.sizeDelta = Vector2.zero;
        var clblText = clbLabel.AddComponent<Text>();
        clblText.text = "领取";
        clblText.fontSize = 18;
        clblText.fontStyle = FontStyle.Bold;
        clblText.color = Color.white;
        clblText.alignment = TextAnchor.MiddleCenter;
        clblText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

        // Completed overlay (hidden by default)
        var completedOverlay = CreateUI("CompletedOverlay", itemPrefab.transform);
        var coRect = completedOverlay.GetComponent<RectTransform>();
        coRect.anchorMin = coRect.anchorMax = Vector2.zero;
        coRect.anchorMin = Vector2.zero; coRect.anchorMax = Vector2.one;
        coRect.sizeDelta = Vector2.zero;
        var coImg = completedOverlay.AddComponent<Image>();
        coImg.color = new Color(0.7f, 0.65f, 0.55f, 0.4f);
        completedOverlay.SetActive(false);

        // Add AchievementItemUI to prefab
        var itemUI = itemPrefab.AddComponent<TowerDefense.UI.AchievementItemUI>();

        // ====== Claim All Button ======
        var claimAllBtn = CreateUI("ClaimAllBtn", mainContainer.transform);
        var caRect = claimAllBtn.GetComponent<RectTransform>();
        caRect.anchorMin = new Vector2(0, 0);
        caRect.anchorMax = new Vector2(0, 0);
        caRect.pivot = new Vector2(0, 0);
        caRect.sizeDelta = new Vector2(160, 40);
        caRect.anchoredPosition = new Vector2(10, 10);
        var caImg = claimAllBtn.AddComponent<Image>();
        caImg.color = new Color(1f, 0.78f, 0.2f, 1f); // gold
        var caBtn = claimAllBtn.AddComponent<Button>();
        var caLabel = CreateUI("Label", claimAllBtn.transform);
        var calRect = caLabel.GetComponent<RectTransform>();
        calRect.anchorMin = calRect.anchorMax = Vector2.zero;
        calRect.anchorMin = Vector2.zero; calRect.anchorMax = Vector2.one;
        calRect.sizeDelta = Vector2.zero;
        var calText = caLabel.AddComponent<Text>();
        calText.text = "一键领取";
        calText.fontSize = 20;
        calText.fontStyle = FontStyle.Bold;
        calText.color = Color.white;
        calText.alignment = TextAnchor.MiddleCenter;
        calText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

        // ====== Wire up AchievementPanel component ======
        var ap = panelRoot.AddComponent<TowerDefense.UI.AchievementPanel>();

        // Use SerializedObject to assign references
        var so = new SerializedObject(ap);
        so.FindProperty("_panel").objectReferenceValue = panelRoot;
        so.FindProperty("_closeButton").objectReferenceValue = cbButton;
        so.FindProperty("_titleText").objectReferenceValue = tText;
        so.FindProperty("_totalCountText").objectReferenceValue = tcText;
        so.FindProperty("_totalProgressSlider").objectReferenceValue = psSlider;
        so.FindProperty("_totalPercentText").objectReferenceValue = pctTxt;
        so.FindProperty("_tabAll").objectReferenceValue = tabBtns[0];
        so.FindProperty("_tabGrowth").objectReferenceValue = tabBtns[1];
        so.FindProperty("_tabBattle").objectReferenceValue = tabBtns[2];
        so.FindProperty("_tabCollection").objectReferenceValue = tabBtns[3];
        so.FindProperty("_tabExploration").objectReferenceValue = tabBtns[4];
        so.FindProperty("_tabFun").objectReferenceValue = tabBtns[5];
