args.script:
// Wire the 成就 button to open AchievementPanel
var canvas = UnityEngine.GameObject.Find("Canvas");
if (canvas == null) { UnityEngine.Debug.LogError("Canvas not found"); return; }

var achPanelGO = canvas.transform.Find("AchievementPanel");
if (achPanelGO == null) { UnityEngine.Debug.LogError("AchievementPanel not found"); return; }

var achPanel = achPanelGO.GetComponent<TowerDefense.UI.AchievementPanel>();
if (achPanel == null) { UnityEngine.Debug.LogError("AchievementPanel component not found"); return; }

// Find the 成就 button in the bottom navigation
var achBtn = canvas.transform.Find("底部导航/成就");
if (achBtn == null)
{
    // Try alternative paths
    foreach (UnityEngine.Transform child in canvas.transform)
    {
        if (child.name.Contains("成就"))
        {
            achBtn = child;
            break;
        }
    }
}

if (achBtn != null)
{
    var btn = achBtn.GetComponent<UnityEngine.UI.Button>();
    if (btn != null)
    {
        btn.onClick.RemoveAllListeners();
        btn.onClick.AddListener(() => achPanel.OpenPanel());
        UnityEngine.Debug.Log("[WireAchievement] 成就 button wired to AchievementPanel.OpenPanel()");
    }
    else
    {
        UnityEngine.Debug.LogWarning("[WireAchievement] 成就 has no Button component");
    }
}
else
{
    UnityEngine.Debug.LogWarning("[WireAchievement] Could not find 成就 button in Canvas");
}

