void Search(UnityEngine.Transform t, int depth)
{
    if (t.name.Contains("成就") || t.name.Contains("achieve") || t.name.Contains("Achieve"))
        results.Add($"{new string(' ', depth * 2)}{t.name} (parent: {t.parent?.name})");
    foreach (UnityEngine.Transform c in t)
        Search(c, depth + 1);
}
Search(canvas.transform, 0);
foreach (var r in results) UnityEngine.Debug.Log(r);
if (results.Count == 0) UnityEngine.Debug.Log("No 成就 found in Canvas hierarchy");

