using UnityEngine;
using UnityEditor;
using System.IO;

// Organize generated sprites into AchievementUI folder
var srcDir = "Assets/TJGenerators/History";
var dstDir = "Assets/AchievementUI";

if (!AssetDatabase.IsValidFolder("Assets/AchievementUI"))
    AssetDatabase.CreateFolder("Assets", "AchievementUI");

// Move and rename sprites
var moves = new (string src, string dst)[]
{
    ("Sprite_20260526_103331.png", "ach_panel_bg.png"),      // Panel background
    ("Sprite_20260526_103338.png", "ach_tab_green.png"),     // Green active tab
    ("Sprite_20260526_103354.png", "ach_btn_claim.png"),     // Gold claim button
    ("Sprite_20260526_103359.png", "ach_icon_frame.png"),    // Hexagonal frame
    ("Sprite_20260526_103404.png", "ach_header.png"),        // Header bar
    ("Sprite_20260526_103539.png", "ach_icon_trophy.png"),   // Trophy (成长)
    ("Sprite_20260526_103540.png", "ach_icon_swords.png"),   // Swords (战斗)
    ("Sprite_20260526_103541.png", "ach_icon_tree.png"),     // Tree (收集)
    ("Sprite_20260526_103542.png", "ach_icon_flag.png"),     // Flag (探索)
    ("Sprite_20260526_103543.png", "ach_icon_wizardhat.png"),// Wizard hat (趣味)
    ("Sprite_20260526_103645.png", "ach_icon_gold_trophy.png") // Gold trophy (general)
};

int moved = 0;
foreach (var m in moves)
{
    var srcPath = Path.Combine(srcDir, m.src);
    var dstPath = Path.Combine(dstDir, m.dst);
    if (File.Exists(srcPath) && !File.Exists(dstPath))
    {
        File.Copy(srcPath, dstPath);
        moved++;
    }
    else if (File.Exists(srcPath) && File.Exists(dstPath))
    {
        // Already exists, skip
    }
}

AssetDatabase.Refresh();

// Set all imported textures to Sprite type
foreach (var m in moves)
{
    var dstPath = Path.Combine(dstDir, m.dst);
    var importer = AssetImporter.GetAtPath(dstPath) as TextureImporter;
    if (importer != null && importer.textureType != TextureImporterType.Sprite)
    {
        importer.textureType = TextureImporterType.Sprite;
        importer.spriteImportMode = SpriteImportMode.Single;
        importer.SaveAndReimport();
    }
}

Debug.Log($"[OrganizeAchievement] Moved {moved} sprites to {dstDir}");

