using UnityEngine;
using UnityEditor;
using UnityEditor.SceneManagement;

public static class RebuildAchievementUI2
{
    [MenuItem("Tools/Rebuild Achievement UI v2")]
    public static void Rebuild()
    {
        var canvas = GameObject.Find("Canvas");
        if (canvas == null) { Debug.LogError("Canvas not found"); return; }

        var old = canvas.transform.Find("AchievementPanel");
        if (old != null) Object.DestroyImmediate(old.gameObject);

        var bgSprite = LoadSprite("Assets/AchievementUI/ach_panel_bg.png");
        var tabSprite = LoadSprite("Assets/AchievementUI/ach_tab_green.png");
        var claimSprite = LoadSprite("Assets/AchievementUI/ach_btn_claim.png");
        var frameSprite = LoadSprite("Assets/AchievementUI/ach_icon_frame.png");
        var headerSprite = LoadSprite("Assets/AchievementUI/ach_header.png");
        var iconTrophy = LoadSprite("Assets/AchievementUI/ach_icon_trophy.png");
        var iconSwords = LoadSprite("Assets/AchievementUI/ach_icon_swords.png");
        var iconTree = LoadSprite("Assets/AchievementUI/ach_icon_tree.png");
        var iconFlag = LoadSprite("Assets/AchievementUI/ach_icon_flag.png");
        var iconHat = LoadSprite("Assets/AchievementUI/ach_icon_wizardhat.png");
        var iconGoldTrophy = LoadSprite("Assets/AchievementUI/ach_icon_gold_trophy.png");

        var cRect = canvas.GetComponent<RectTransform>();
        float W = cRect.rect.width, H = cRect.rect.height;

        // Panel root
        var panelRoot = NewUI("AchievementPanel", canvas.transform);
        SetStretch(panelRoot, W, H);
        panelRoot.AddComponent<CanvasGroup>();
        var pImg = panelRoot.AddComponent<UnityEngine.UI.Image>();
        pImg.color = new Color(0, 0, 0, 0.55f);
        panelRoot.SetActive(false);

        // Main Container
        var main = NewUI("MainContainer", panelRoot.transform);
        SetCenter(main, 1500, 780);
        var mcImg = main.AddComponent<UnityEngine.UI.Image>();
        if (bgSprite != null) { mcImg.sprite = bgSprite; mcImg.color = Color.white; }
        else mcImg.color = new Color(0.96f, 0.94f, 0.88f 1f);

        // Header
        var header = NewUI("Header", main.transform);
        SetTopStretch(header, 70);
        var hImg = header.AddComponent<UnityEngine.UI.Image>();
        if (headerSprite != null) { hImg.sprite = headerSprite; hImg.color = Color.white; }
        else hImg.color = new Color(0.45f, 0.75f, 0.3f, 1f);

        var trophyIcon = NewUI("TrophyIcon", header.transform);
        SetAnchor(trophyIcon, new Vector2(0, 0.5f), new Vector2(0, 0.5f), new Vector2(1, 0.5f), new Vector2(50, 50), new Vector2(-60, 0));
        var tiImg = trophyIcon.AddComponent<UnityEngine.UI.Image>();
        if (iconGoldTrophy != null) { tiImg.sprite = iconGoldTrophy; tiImg.color = Color.white; }

        var title = NewUI("Title", header.transform);
        SetCenter(title, 200, 50);
        var tText = AddTxt(title, "\u6210 \u5c31", 32, Color.white, true);

        var closeBtnGO = NewUI("CloseBtn", header.transform);
        SetAnchor(closeBtnGO, new Vector2(1, 0.5f), new Vector2(1, 0.5f), new Vector2(1, 0.5f), new Vector2(50, 50), new Vector2(-15, 0));
        closeBtnGO.AddComponent<UnityEngine.UI.Image>().color = new Color(1, 1, 1, 0.3f);
        var closeBtn = closeBtnGO.AddComponent<UnityEngine.UI.Button>();
        AddTxt(NewUI("X", closeBtnGO.transform), "\u2715", 28, Color.white, false);

        // Progress Area
        var progArea = NewUI("ProgressArea", main.transform);
        SetAnchor(progArea, new Vector2(0, 1), new Vector2(1, 1), new Vector2(0.5f, 1), new Vector2(-20, 50), new Vector2(0, -80));
        progArea.AddComponent<UnityEngine.UI.Image>().color = new Color(0.92f, 0.9f, 0.82f, 1f);

        var tcGO = NewUI("TotalCount", progArea.transform);
        SetAnchor(tcGO, new Vector2(0, 0.5f), new Vector2(0, 0.5f), new Vector2(0, 0.5f), new Vector2(80, 30), new Vector2(15, 0));
        var tcText = AddTxt(tcGO, "0/28", 18, new Color(0.3f, 0.25f, 0.15f, 1f), true);

        var psGO = NewUI("ProgressSlider", progArea.transform);
        SetCenter(psGO, 900, 16);
        var psSlider = psGO.AddComponent<UnityEngine.UI.Slider>();
        psGO.AddComponent<UnityEngine.UI.Image>().color = new Color(0.8f, 0.75f, 0.65f, 1f);
        psSlider.targetGraphic = psGO.GetComponent<UnityEngine.UI.Image>();
        var fa = NewUI("FillArea", psGO.transform); SetCenter(fa, 0, 0);
        var fill = NewUI("Fill", fa.transform); SetStretchZero(fill);
        fill.AddComponent<UnityEngine.UI.Image>().color = new Color(0.45f, 0.8f, 0.3f, 1f);
        psSlider.fillRect = fill.GetComponent<RectTransform>(); psSlider.handleRect = null;

        var pctGO = NewUI("Percent", progArea.transform);
        SetAnchor(pctGO, new Vector2(1, 0.5f), new Vector2(1, 0.5f), new Vector2(1, 0.5f), new Vector2(60, 30), new Vector2(-15, 0));
        var pctText = AddTxt(pctGO, "0%", 16, new Color(0.45f, 0.75f, 0.3f, 1f), false);

        // Left Tabs
        var leftPanel = NewUI("LeftPanel", main.transform);
        var lpRT = leftPanel.GetComponent<RectTransform>();
        lpRT.anchorMin = new Vector2(0, 0); lpRT.anchorMax = new Vector2(0, 1);
