        var headerSprite = LoadSprite("Assets/AchievementUI/ach_header.png");
        var iconTrophy = LoadSprite("Assets/AchievementUI/ach_icon_trophy.png");
        var iconSwords = LoadSprite("Assets/AchievementUI/ach_icon_swords.png");
        var iconTree = LoadSprite("Assets/AchievementUI/ach_icon_tree.png");
        var iconFlag = LoadSprite("Assets/AchievementUI/ach_icon_flag.png");
        var iconHat = LoadSprite("Assets/AchievementUI/ach_icon_wizardhat.png");
        var iconGoldTrophy = LoadSprite("Assets/AchievementUI/ach_icon_gold_trophy.png");

        var cRect = canvas.GetComponent<RectTransform>();
        float W = cRect.rect.width, H = cRect.rect.height;

        // Panel root
        var panelRoot = NewUI("AchievementPanel", canvas.transform);
        SetStretch(panelRoot, W, H);
        panelRoot.AddComponent<CanvasGroup>();
